"use client";

import { useState } from "react";
import Link from "next/link";
import { Button } from "@/components/ui/button";
import { Menu, X } from "lucide-react";
import { NAV_LINKS } from "@/constants";
import { APP_CONFIG } from "@/config/app.config";
import { Logo } from "@/components/Logo";

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);

  const handleNavClick = () => {
    setIsOpen(false);
  };

  return (
    <nav className="fixed top-0 left-0 right-0 z-50 bg-background/60 backdrop-blur-xl border-b border-border/40 transition-all duration-300">
      <div className="container mx-auto px-4">
        <div className="flex items-center justify-between h-20 lg:h-24">
          {/* Logo */}
          <Link href="/" className="flex items-center gap-2 hover:opacity-80 transition-all hover:scale-105 active:scale-95">
            <Logo size="md" showText={true} textClassName="hidden sm:inline font-bold tracking-tight text-xl" />
          </Link>

          {/* Desktop Navigation */}
          <div className="hidden lg:flex items-center gap-10">
            {NAV_LINKS.map((link) => (
              <Link
                key={link.name}
                href={link.href}
                className="text-sm font-semibold text-muted-foreground hover:text-primary transition-all relative group"
              >
                {link.name}
                <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-primary transition-all group-hover:w-full" />
              </Link>
            ))}
          </div>

          {/* Desktop CTA */}
          <div className="hidden lg:flex items-center gap-6">
            <Button
              variant="ghost"
              className="font-bold text-muted-foreground hover:text-foreground"
              onClick={() =>
                window.open(APP_CONFIG.links.contactWhatsApp, "_blank")
              }
            >
              Support
            </Button>
            <Button
              variant="hero"
              className="rounded-full px-8 shadow-soft hover:shadow-glow"
              onClick={() =>
                window.open(APP_CONFIG.links.bookSlot, "_blank")
              }
            >
              Try for Free
            </Button>
          </div>

          {/* Mobile Menu Button */}
          <button
            className="lg:hidden p-3 rounded-2xl bg-muted/50 text-foreground transition-all hover:bg-muted"
            onClick={() => setIsOpen(!isOpen)}
            aria-label="Toggle menu"
          >
            {isOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
          </button>
        </div>

        {/* Mobile Menu */}
        {isOpen && (
          <div className="lg:hidden py-8 border-t border-border/50 animate-fade-up bg-background/95 backdrop-blur-2xl rounded-b-[2rem] shadow-card">
            <div className="flex flex-col gap-6 px-4">
              {NAV_LINKS.map((link) => (
                <Link
                  key={link.name}
                  href={link.href}
                  className="text-2xl font-bold text-foreground hover:text-primary transition-colors"
                  onClick={handleNavClick}
                >
                  {link.name}
                </Link>
              ))}
              <div className="flex flex-col gap-4 pt-8 border-t border-border/50">
                <Button
                  variant="hero"
                  size="xl"
                  className="w-full rounded-2xl font-bold ring-offset-background"
                  onClick={() => {
                    handleNavClick();
                    window.open(APP_CONFIG.links.bookSlot, "_blank");
                  }}
                >
                  Book a Demo
                </Button>
              </div>
            </div>
          </div>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
